import{_,o as e,c as a,ag as t}from"./chunks/framework.DPqexil4.js";const m=JSON.parse('{"title":"第183章 他有春叶夏雷秋风冬雪","description":"","frontmatter":{},"headers":[],"relativePath":"剑来/正文/0100-0199/第0183章-他有春叶夏雷秋风冬雪.md","filePath":"剑来/正文/0100-0199/第0183章-他有春叶夏雷秋风冬雪.md"}'),r={name:"剑来/正文/0100-0199/第0183章-他有春叶夏雷秋风冬雪.md"};function o(n,p,s,c,i,d){return e(),a("div",null,[...p[0]||(p[0]=[t('<h1 id="第183章-他有春叶夏雷秋风冬雪" tabindex="-1">第183章 他有春叶夏雷秋风冬雪 <a class="header-anchor" href="#第183章-他有春叶夏雷秋风冬雪" aria-label="Permalink to &quot;第183章 他有春叶夏雷秋风冬雪&quot;">​</a></h1><p>临近年关，天寒地冻，泥瓶巷的狭窄泥路，变得十分坚硬。</p><p>陈平安深呼吸一口气，望向那个高大背影，轻声喊道：“李大哥。”</p><p>李希圣没有转身，微笑道：“不用担心，我能够应付。就算我不是他的对手，小镇有小镇的规矩，不会由着他乱来。”</p><p>自称曹峻的年轻剑客笑呵呵道：“你是说大骊朝廷，还是兵家阮邛？如果是前者，我劝你们死了这条心，大骊宋氏如果真有骨气，就不会当缩头乌龟。如果是阮邛，哈哈，容我先卖个关子，你们大可以拭目以待。”</p><p>曹峻看着那位貌如冠玉的青衫书生，相比自己的貌似年轻，对方是货真价实的年纪轻轻，这让曹峻有点不爽快，他拇指抵住腰间短剑剑柄，“真要打？有些亏，认了就认了，说不定事后发现因祸得福。”</p><p>李希圣微笑道：“既然你说你的的道理，全在剑鞘里，那我可以听听看。”</p><p>“听闻骊珠洞天之前术法禁绝，如今洞天破碎下坠，才一年功夫，你就已经跻身中五境，很不错了。”</p><p>曹峻目露赞赏，但是很快摇了摇头，啧啧道：“可惜了。”</p><p>李希圣伸出一只手掌，“请。”</p><p>曹峻忍俊不禁道：“井底之蛙，不知天高。既然咱们不算生死之战，那我就把境界压一压，省得你的生平第一战，输得太过不甘心。”</p><p>李希圣笑而不言。</p><p>“等你以后出了井口，就会发现我这样的人物，当得起……”曹峻脚尖一点，弯腰前冲，大笑出声，一旦选择出手，这个笑意吟吟的年轻剑客，气势骤变，狭窄逼仄的巷弄回荡起后续言语，“厚道两字啊！”</p><p>一道绚烂白光爆炸开口，疯狂四散的剑气，瞬间弥漫整条巷弄，加上曹峻的身形太过迅猛急速，使得他的模糊身影融入其中，不易察觉，让人错以为像一条暴雨过后的山涧洪水，以巷弄为河床，疯狂涌向处于下游的李希圣一行人。</p><p>白茫茫一片，气势汹汹的剑气流水之中，依稀可见一抹更加凝聚的雪白光彩，如一尾白鱼悄然游走于溪水。</p><p>流水停滞。</p><p>李希圣看似不急不缓，侧过身，抬手挥袖，伸向那尾仿佛白鱼的雪亮短剑。</p><p>然后轻轻精准握住了曹峻的持剑手腕。</p><p>曹峻微微一笑，松开手指，距离李希圣胸膛尚有两三尺的短剑，嗖一下，直刺李希圣心口。</p><p>李希圣神色从容，左手双指并拢于身前。</p><p>竟是在千钧一发之际，刚好夹住了那条白鱼。</p><p>白鱼翻身滚动。</p><p>剑刃随之拧转。</p><p>李希圣只得后退，曹峻欺身而近，持剑之手已经出拳，直击李希圣脖颈。</p><p>李希圣以手肘抵住曹峻拳头的同时，那尾白鱼已经激射而至，李希圣抖了抖另外一只手的手腕，大袖摇晃。</p><p>那尾白鱼，自投罗网。</p><p>曹峻嗤笑一声，一脚踹中李希圣腹部，踹得青衫书生后退四五步。</p><p>他没有趁势追击，大大方方站在原地，一手负后，一手潇洒绝伦。</p><p>李希圣止住后退颓势，脸色微白，曹峻虽是剑修，可这一脚势大力沉，丝毫不逊色五境巅峰的纯粹武夫，这本就是剑修和兵家修士的恐怖之处，炼气淬体两不误，所以李希圣挨了这么一下，并不好受，体内气机的流转必然受到一定程度的波及。</p><p>李希圣那只兜住曹峻飞剑的大袖之内，砰砰作响，连绵不绝，然后发出细微的丝帛撕裂声响，之后丝丝缕缕的雪白剑光，从缝隙之间渗透而出。</p><p>袖有乾坤的李希圣那只手，五指或弯曲如弓，或笔直如剑戟，飞快掐出一个道家法诀，在心中默念一个字：“镇！”</p><p>原本已经鼓荡紧绷、纷乱异常的袖口，顿时安静下来。</p><p>飞剑疾速撞击衣袖的声响，变作微微颤抖的嗡嗡嘶鸣。</p><p>曹峻对此毫不意外，笑道：“七。”</p><p>李希圣整只袖口，自手肘以下，瞬间破碎，手腕附近，剑光大震。</p><p>好似月光满手的绝美风景，却蕴含着莫大的凶险杀机。</p><p>李希圣掐诀的五指随之变换，成为名副其实的握诀，在所有人看不见的手心，掌纹如水流微微晃动，改变轨迹。</p><p>李希圣这条胳膊瞬间焕发出一阵雾蒙蒙的青紫光彩。</p><p>剑锋疯狂萦绕李希圣手臂的那条白色游鱼，它带起的剑气跟李希圣的散发出的青紫之气，相互敲击出清脆的金石声，密集攒簇，震人耳膜。</p><p>以至于泥瓶巷一侧的高墙，和另一侧老宅的院门矮墙，不断有灰尘泥屑簌簌而落。</p><p>曹峻原本细眯如缝的那双丹凤眼眸，睁开些许，调侃道：“有点意思，道家法诀号称千千万，我见识过就不下两百种，还真没见过你这么简单又好用的。姓李的，你这六境修为，也太厚实了些，从来只有六境剑修欺负七境练气士，哪里有你这种六境练气士硬扛七境剑修的道理，传出去，我曹峻岂不是要被全天下的剑修笑话啊。”</p><p>李希圣在经历过初期的生疏之后，当下已经显得犹有余力，甚至还可以开口笑道：“可能是你的道理还不够……高？”</p><p>这章没有结束，请点击下一页继续阅读！</p><p>曹峻点点头，深以为然，所以满脸笑意地说出一个字，“八！”</p><p>宛如灵活白鱼的飞剑，往主人曹峻那边倒掠回去，然后静止悬停，飞剑瞬间黯淡无光，短剑就只是短剑，没有丝毫剑气流溢，再没有之前的煌煌气势。</p><p>之前给人诡谲感觉的阴冷剑意，摇身一变，变得光明正大。</p><p>飞剑刹那之间凭空消失。</p><p>两人之间的小巷一处院墙上，出现极其细微的痕迹，不过是丁点儿粉末碎屑飘落。</p><p>李希圣右手伸出双指，试图再次握住那柄绕出一个弧度的短剑。</p><p>李希圣突然一扭头。</p><p>下一刻，飞剑在李希圣左侧高墙上钻出一个窟窿。</p><p>飞剑再度消失。</p><p>但是李希圣左侧脸颊上，开始出现一粒血珠，然后逐渐扩大为一条寸余长的血痕。</p><p>果然是如传闻一般，与剑修厮杀，生死只在一线之间。</p><p>李希圣心中默念，“原来这就是八，确实厉害。”</p><p>剑修之战力，之所以能够被公认冠绝于百家练气士，就在于一把温养得当的飞剑，凌厉之处在于“点”，以及最多就是一条线。</p><p>不管一座山岳如何巍峨，何等雄伟，如果想要在峭壁之上钉入一颗钉子，或是凿出一条沟壑来，其实不难。</p><p>同样是练气士当中的异类，即便是既修体魄、又修神魂的兵家修士，都不如剑修与人厮杀，来得干脆利落。</p><p>任你法宝万千，任你神通广大， 我剑修追求一击致命，一剑破万法。</p><p>曹峻始终保持一手负后的自负姿势，一手轻拍长剑剑柄，“你这样的修道天才，肯定是家族寄予厚望的存在，就没有几件防身的宝贝？我可不信。事先说好，不管你出于何种目的，如果继续藏藏掖掖，不愿公之于众，会真的死人，因为我怕自己一不小心打得太高兴了，收不住手，到时候你肯定要死不瞑目。”</p><p>面对敌人的冷嘲热讽，李希圣并不生气，嗓音依旧温醇柔和，“陈平安，可能需要麻烦你们再后退一些，如果能退到四五丈之外，是最好。”</p><p>曹峻抬手使劲一拍额头，满脸委屈道：“大敌当前，还有闲情逸致说废话，我很生气。”</p><p>年轻剑修的谈笑之间，暗藏杀机。</p><p>在曹峻手拍额头发出声响的同时，飞剑已经在那点声响的遮掩之下，真正做到了悄无声息，杀到了李希圣的后背心。</p><p>叮！</p><p>一声空灵悦耳的响动，响彻泥瓶巷。</p><p>曹峻愣了一下，随即大笑道：“这也行？那我可就真不客气啦。”</p><p>李希圣背后浮现出一片青翠竹叶，抵挡住了飞剑的刺杀。</p><p>叮叮叮叮……</p><p>小巷内，李希圣四周响起一大串类似动静。</p><p>除了一张张竹叶，还有桃叶，柳叶，槐叶……</p><p>各种树叶皆青绿。</p><p>曹峻眯眼凝视那处战场。</p><p>李希圣岿然不动，四周全部是高高低低、飘荡起伏的树叶，名为白鱼的短剑则穿梭其中，不断破阵，但是次次无功而返。</p><p>虽然不断有绿叶坠地，瞬间枯黄，可是曹峻着实有些无奈，因为粗略估计那个读书人的树叶，最少也该有百余张。</p><p>所以曹峻心情不太好。</p><p>你这家伙的家里，是卖树叶的啊？就算卖，有人买吗？</p><p>曹峻不愿就此打退堂鼓，他就不信一个小小的六境练气士，能够支撑到最后。同时驾驭这么多张树叶，本来就不简单，练气士需要耗费的心神，极其可观。于是曹峻暗中告诉自己，虽然胜之不武，可勉强当做是一场砥砺剑锋的蠢笨气力活好了，他倒要看看那个读书人能够支撑多久。</p><p>那柄短小却凌厉的飞剑，开始肆无忌惮地横冲直撞。</p><p>小巷内，落叶纷纷，坠地之后便由绿转黄。</p><p>李希圣突然出声提醒道：“咱们如果只是这么打下去，能够打到明年。不然你说过了这把剑的道理，再说说另外那把的？如果可以的话，一并祭出本命飞剑好了。不管如何，好歹先分出个胜负。因为我朋友还要赶路。”</p><p>曹峻蓦然瞪大眼睛，终于不再笑脸示人，“你不吹牛会死啊？”</p><p>李希圣叹了口气，不再说话。</p><p>他只是抖了抖那只仅存的袖子，从袖子里抖落出了一大堆匪夷所思的玩意儿。</p><p>有所剩不多的春叶，但是除此之外，还有一粒粒指甲盖大小的夏雷，有一缕缕长不过手指的秋风，有一片片鹅毛大小的冬雪。</p><p>对手有一剑可破万法。</p><p>怎么办？</p><p>我是不是可以积攒出一万零一法？</p><p>于是这个名为李希圣的年轻书生，哪怕他如今不过是刚刚跻身中五境，却已经有了春叶夏雷秋风冬雪，更何况他还有其它，而且很多。</p>',89)])])}const f=_(r,[["render",o]]);export{m as __pageData,f as default};
